1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const POST_FIRST_CONTRACT_MULTIPLIER = 0.85;
7	const CURSED_MULTIPLIER = 1.5;
8	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
9	const LOYALTY_MULTIPLIER = 0.8;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const ADMIN_FEE = 5;
12	
13	// Three alike pieces of a "building-block" item (rune, moonstone, …) pool
14	// to a single unit priced at this fixed tier, irrespective of the per-piece
15	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
16	// is conceptually a separate pricing rule from the per-item ladder.
17	const BUILDING_BLOCK_PRICE = 60;
18	
19	const BASE_PRICE: Record<string, number> = {
20	  sword: 100,
21	  staff: 80,
22	  amulet: 60,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const POOLED_TYPES = new Set(["rune", "moonstone"]);
29	
30	function itemModifierMultiplier(item: Item): number {
31	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
32	  const highEnchantment =
33	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
34	  return cursed * highEnchantment;
35	}
36	
37	// MHPCO always rounds the euro value of a discounted/loaded price upward
38	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
39	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
40	// bumped up a euro by a 110.00000000000001 representation.
41	function ceilInMhpcoFavor(value: number): number {
42	  return Math.ceil(Number(value.toFixed(10)));
43	}
44	
45	// Sum of per-item base prices (with item-attribute multipliers applied)
46	// for a single quote. Building-block items (rune today, moonstone in cycle
47	// 13) are pooled in groups of three at BUILDING_BLOCK_PRICE; leftovers fall
48	// back to the per-piece BASE_PRICE.
49	function quoteItemsSubtotal(items: Item[]): number {
50	  let subtotal = 0;
51	  const pooledCounts = new Map<string, number>();
52	  for (const item of items) {
53	    if (POOLED_TYPES.has(item.type)) {
54	      pooledCounts.set(item.type, (pooledCounts.get(item.type) ?? 0) + 1);
55	    } else {
56	      subtotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
57	    }
58	  }
59	  for (const [type, count] of pooledCounts) {
60	    const buildingBlocks = Math.floor(count / 3);
61	    const loose = count % 3;
62	    subtotal += buildingBlocks * BUILDING_BLOCK_PRICE + loose * BASE_PRICE[type];
63	  }
64	  return subtotal;
65	}
66	
67	export function runScenario(scenario: unknown): unknown {
68	  const { customer, steps } = scenario as Scenario;
69	  const loyaltyMultiplier =
70	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
71	  let quoteIndex = 0;
72	  const results = steps.map((step) => {
73	    const itemsSubtotal = quoteItemsSubtotal(step.items);
74	    const contractMultiplier =
75	      quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : POST_FIRST_CONTRACT_MULTIPLIER;
76	    quoteIndex += 1;
77	    const premium =
78	      ceilInMhpcoFavor(itemsSubtotal * loyaltyMultiplier * contractMultiplier) +
79	      ADMIN_FEE;
80	    return { premium };
81	  });
82	  return { results };
83	}
